import { useEffect } from 'react';

type useCosUploadProps = {
    getCredential: () => Promise<any>;
    useFileContentType?: boolean;
};

/**
 * COS上传的hooks
 * @param {useCosUploadProps} { getCredential, useFileContentType }
 * @return {*}
 */
export const useCosUpload = ({ getCredential, useFileContentType }: useCosUploadProps) => {
    useEffect(() => {
        if (typeof (window as any).CosAuth !== 'function') {
            const myScript = document.createElement('script');
            // 设置标签的src属性
            myScript.src = 'https://romerx-cos.spotterio.com/crucial_js/cos-auth.min.js';
            // 明确设置为同步加载
            myScript.async = false;
            // 追加到body标签的最下面
            document.body.append(myScript);
            return () => {
                // 组件即将卸载时，移除标签
                myScript.remove();
            };
        }
        return () => { }
    }, []);
    return async (file: File, fileName: string) => {
        const { data } = await getCredential();

        const Authorization = (window as any).CosAuth({
            SecretId: data.secretId,
            SecretKey: data.secretKey,
            Method: 'PUT',
            Pathname: `${data.fileUrlBase.split('.com')[1]}${fileName}`
        });

        return fetch(`${data.fileUrlBase}${fileName}`, {
            method: 'PUT', // *GET, POST, PUT, DELETE, etc.
            headers: {
                Accept: 'application/octet-stream, text/plain, */*',
                'Content-Type': useFileContentType ? file.type : 'application/octet-stream',
                Authorization,
                'x-cos-security-token': data.sessionToken
            },
            body: file
        });
    };
};
